```class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int result = 0;
        for (int i = 0; i < nums.size(); i += k) {
            int left = i, right = i + k - 1;
            int sum = 0;
            while (right >= left) {
                sum ^= nums[right];
                right--;
            }
            result = max(result, abs(sum));
        }
        return result;
    }
};
